import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Cpu, Terminal, ShieldCheck, Lock } from 'lucide-react';
import toast from 'react-hot-toast';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);

  const { login } = useAuth();
  const { isDarkMode } = useTheme(); 
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('FIELDS_REQUIRED');
    
    const tid = toast.loading('SYNCHRONIZING_NODE...');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: tid });
      navigate('/dashboard');
    } catch (err) {
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: tid });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="vault-card reveal-node">
      {/* 🛰️ Institutional Laser Scan */}
      <div className="animate-laser" />

      {/* 🚀 Brand Identity */}
      <div className="flex flex-col items-center mb-10">
        <div className={`p-4 rounded-2xl mb-4 transition-colors duration-300 ${
          isDarkMode ? 'bg-emerald-500/10' : 'bg-emerald-600/5'
        }`}>
          <Cpu className="text-[var(--accent-primary)] animate-pulse" size={32} />
        </div>
        <h2 className="text-2xl font-light tracking-[0.3em] uppercase text-[var(--text-primary)]">
          Access_Gate
        </h2>
        <p className="text-[10px] text-[var(--text-muted)] tracking-[0.4em] uppercase mt-2">
          Secure_Node_v3.2
        </p>
      </div>

      <form onSubmit={handleLogin} className="space-y-6">
        {/* Email Field */}
        <div className="flex flex-col gap-2">
          <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest ml-1 flex items-center gap-2">
            <Terminal size={12} /> Registry_Email
          </label>
          <input 
            type="email" 
            className="cyber-input" 
            placeholder="operator@finify.ai"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
        </div>

        {/* Password Field */}
        <div className="flex flex-col gap-2 relative">
          <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest ml-1 flex items-center gap-2">
            <Lock size={12} /> Security_Key
          </label>
          <div className="relative">
            <input 
              type={showPass ? "text" : "password"} 
              className="cyber-input" 
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
            <button 
              type="button" 
              onClick={() => setShowPass(!showPass)}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-[var(--text-muted)] hover:text-[var(--accent-primary)] transition-colors"
            >
              {showPass ? <FaEyeSlash size={16} /> : <FaEye size={16} />}
            </button>
          </div>
        </div>

        {/* Action Button */}
        <button 
          type="submit" 
          disabled={loading}
          className="cyber-btn mt-4 group"
        >
          {loading ? (
            <span className="animate-pulse">SYNCHRONIZING...</span>
          ) : (
            <>
              <ShieldCheck size={18} className="group-hover:scale-110 transition-transform" />
              <span>Connect_to_Terminal</span>
            </>
          )}
        </button>
      </form>

      {/* Footer UX */}
      <div className="mt-10 pt-6 border-t border-[var(--surface-border)] text-center">
        <p className="text-[10px] text-[var(--text-muted)] mb-3">
          New Operator?
        </p>
        <Link 
          to="/register" 
          className="text-[10px] text-[var(--accent-primary)] font-bold uppercase tracking-widest hover:underline transition-all"
        >
          Initialize_New_Identity
        </Link>
      </div>
    </div>
  );
};

export default LoginPage;
